 assert.deepEqual(results, { 0: 0, 1: 1, 2: 2, 3: 3 });

var graph = [
  [0, 1],
  [1, 0]
];
var results = bfs(graph, 0);
assert.deepEqual(results, { 0: 0, 1: 1 });

